// Cycle through array indices — useful for carousels
const items = ['a', 'b', 'c', 'd'];
let current = 0;

function next() {
  current = (current + 1) % items.length; // wraps: 3 → 0
}

// Check even/odd
const isEven = n => n % 2 === 0;

// Angular: striped table rows
// [class.odd]="i % 2 !== 0"  in *ngFor

// Evaluation: left to right; stops at first falsy
false && anything    // false — right side not evaluated
0 && 'hello'         // 0     — 0 is falsy
null && fn()         // null  — fn() NOT called
'hi' && 42           // 42    — 'hi' is truthy, returns right side
{} && 'value'        // 'value' — {} is truthy

// Practical uses
const name = user && user.name;      // safe access (prefer ?. today)
isAdmin && performAdminAction();     // conditional execution
condition && <Component />           // React/Angular template pattern

// Evaluation: left to right; stops at first truthy
true || anything     // true  — right side not evaluated
'hello' || 'default' // 'hello' — truthy, returns it
null || 'default'    // 'default' — null is falsy
0 || 'default'       // 'default' — 0 is falsy (GOTCHA for numbers!)
'' || 'default'      // 'default' — '' is falsy (GOTCHA for strings!)

// || as fallback — but beware of 0 and ''
const timeout = config.timeout || 5000; // BUG if timeout is 0 (valid)
const port    = options.port    || 3000; // BUG if port is 0 (invalid but...)

let x = 10;
x += 5;   // x = 15  (x = x + 5)
x -= 3;   // x = 12
x *= 2;   // x = 24
x /= 4;   // x = 6
x %= 4;   // x = 2
x **= 3;  // x = 8  (x = x ** 3)

// Logical assignment (ES2021)
let config = { timeout: null, label: '' };

// ??= — assign only if null or undefined
config.timeout ??= 5000;  // 5000 (was null)
config.label   ??= 'OK';  // '' stays '' (not null/undefined)

// ||= — assign if falsy
let name = '';
name ||= 'Guest'; // 'Guest' ('' is falsy)

// &&= — assign if truthy
let user = { admin: true };
user.admin &&= checkPermissions(); // only calls checkPermissions if admin is truthy

// Destructuring assignment
let [a, b] = [1, 2];
[a, b] = [b, a]; // swap without temp

// condition ? valueIfTrue : valueIfFalse
const label = isActive ? 'Active' : 'Inactive';
const price = quantity > 10 ? discountedPrice : regularPrice;

// Nested ternary — use with care, keep to 2 levels max
const status =
  isLoading ? 'Loading...' :
  hasError  ? 'Error!'     :
  data      ? 'Loaded'     : 'Empty';

// In Angular templates
// {{ isAdmin ? 'Admin' : 'User' }}
// [class.active]="isSelected ? true : false"  — better: [class.active]="isSelected"
// [ngClass]="hasError ? 'error-state' : 'default-state'

// Spread array
const a = [1, 2, 3];
const b = [4, 5, 6];
const combined = [...a, ...b];        // [1, 2, 3, 4, 5, 6]
const copy     = [...a];              // shallow copy
const prepend  = [0, ...a];           // [0, 1, 2, 3]

// Spread in function call
Math.max(...a);  // same as Math.max(1, 2, 3) → 3

// Spread object (ES2018)
const defaults = { timeout: 5000, retries: 3 };
const config   = { ...defaults, timeout: 10000 }; // override timeout
// { timeout: 10000, retries: 3 }

// Last spread wins for duplicate keys
const merged = { ...a, ...b };  // b's keys override a's

// Angular: immutable state update
this.items = [...this.items, newItem];
this.user  = { ...this.user, name: 'Bob' };

// Rest in function parameters — must be last
function sum(first, ...rest) {
  return rest.reduce((acc, n) => acc + n, first);
}
sum(1, 2, 3, 4); // 10

// Rest in destructuring
const [head, ...tail] = [1, 2, 3, 4];
// head = 1, tail = [2, 3, 4]

const { id, name, ...rest } = user;
// id and name extracted, rest = { role, age, ... }

const user = null;

// Without optional chaining — throws TypeError
// user.address.city

// With optional chaining — returns undefined safely
user?.address?.city        // undefined

// Arrays
arr?.[0]                   // undefined if arr is null/undefined

// Functions
obj.method?.()             // undefined if method doesn't exist

// Chained with nullish coalescing
const city = user?.address?.city ?? 'Unknown';

// Angular use cases
// {{ user?.name }}                               — template
// [disabled]="form.controls['email']?.invalid"  — reactive forms
// this.route.snapshot.paramMap?.get('id')        — router params

// Precedence examples
2 + 3 * 4      // 14 — * before +
(2 + 3) * 4    // 20 — () forces + first

true || false && false  // true — && before ||
(true || false) && false // false

// Common gotcha — + has lower precedence than comparison
2 + 3 > 4    // 5 > 4 → true
typeof 'x' === 'string' // true — typeof then ===

// Ternary has very low precedence
const v = a ? b : c + 1;  // c + 1, not (c + 1) within ternary
// Equivalent to: a ? b : (c + 1)

// Right-to-left associativity: ** and assignment
2 ** 3 ** 2    // 512 — same as 2 ** (3 ** 2) = 2 ** 9
let a = b = 5; // b = 5, then a = 5

// ??= — assign if null or undefined (nullish assignment)
let port = null;
port ??= 3000;   // port is now 3000
let label = '';
label ??= 'OK';  // label stays '' — '' is not null/undefined

// ||= — assign if falsy (OR assignment)
let title = '';
title ||= 'Untitled';  // title is now 'Untitled' ('' is falsy)
let count = 0;
count ||= 10;          // count is now 10 (0 is falsy — often unintended!)

// &&= — assign if truthy (AND assignment)
let user = { name: 'Alice', premium: true };
user.premium &&= checkPremiumStatus(user.id); // only calls if premium is truthy

// Cache initialisation — common pattern
const cache = {};
function getUser(id) {
  cache[id] ??= fetchUser(id); // only fetches if not in cache
  return cache[id];
}

// Angular: lazy initialisation
class ChartComponent {
  private _data: ChartData | null = null;

  get data(): ChartData {
    this._data ??= this.buildChartData(); // build once
    return this._data;
  }
}

// Functional route guard using && and ??
export const authGuard = () => {
  const auth   = inject(AuthService);
  const router = inject(Router);
  // Short-circuit: if logged in, return true; otherwise redirect
  return auth.isLoggedIn() || router.createUrlTree(['/login']);
};

// Component guard combining several operators
canActivate(): boolean {
  const isLoggedIn = this.auth.user !== null;
  const hasRole    = this.auth.user?.roles?.includes('admin') ?? false;
  return isLoggedIn && hasRole;
}

import { map, filter, catchError } from 'rxjs/operators';
import { of } from 'rxjs';

this.productService.getProducts().pipe(
  // Ternary and arithmetic operators inside map
  map(products => products.map(p => ({
    ...p,
    discountedPrice: p.onSale ? p.price * 0.8 : p.price,
    label: p.stock > 0 ? 'In Stock' : 'Out of Stock',
  }))),
  // Optional chaining and ?? in filter
  filter(products => products.length > 0),
  catchError(err => of([])),
).subscribe(products => {
  this.products = products;
  this.total = products.reduce((sum, p) => sum + p.price, 0);
});

// Non-null assertion operator ! — tells TS "this is not null/undefined"
const el = document.getElementById('app')!;   // no null check needed
el.style.display = 'none';                    // TS treats el as HTMLElement

// Use sparingly — you are disabling a safety check
// Better alternative: if (el) { el.style.display = 'none'; }

// Type assertion with as
const input = event.target as HTMLInputElement;
console.log(input.value);

// Angle-bracket assertion (JSX-incompatible, prefer 'as')
const input2 = <HTMLInputElement>event.target;

// satisfies operator (TS 4.9) — validate type without widening
const config = {
  host: 'localhost',
  port: 5432,
} satisfies Partial<DbConfig>;
// config.host is still type 'string' (not widened to string | undefined)

// keyof and typeof (type-level, not runtime)
type UserKeys = keyof User;           // 'id' | 'name' | 'email'
type ConfigType = typeof defaultConfig; // inferred from value
